<?php
namespace Tests\Unit\Domain\Combat;
use App\Domain\Combat\CombatResultStatus;use App\Domain\Combat\CombatSimulator;use App\Domain\Combat\Data\CombatantStats;use App\Domain\Random\RandomNumberGenerator;use PHPUnit\Framework\TestCase;use ReflectionClass;
class SequenceRandom implements RandomNumberGenerator{public $values;public $calls=0;public function __construct(array $v){$this->values=$v;}public function randomInt(int $min,int $max):int{$this->calls++;return array_shift($this->values);}}
class CombatSimulatorTest extends TestCase{private function c($id,$health=20,$attack=10,$speed=1,$accuracy=0,$evasion=0,$critical=0,$multiplier=1.5,$reduction=0){return new CombatantStats($id,$id,$health,$health,$attack,0,$accuracy,$evasion,$critical,$multiplier,$speed,$reduction);}public function test_boundary_hit_miss_and_no_critical_roll_on_miss(){$rng=new SequenceRandom(array_merge([8000,10000,8001,10000],array_fill(0,400,10000)));$r=(new CombatSimulator($rng))->simulate($this->c('character',20,1,1,10),$this->c('monster',20,1,1,0,5));$a=$r->rounds()[0]->actions();$this->assertTrue($a[0]->hit());$this->assertFalse($a[1]->hit());$this->assertNull($a[1]->criticalRoll());$this->assertFalse($a[1]->critical());}public function test_critical_and_single_final_rounding(){$rng=new SequenceRandom([1,1]);$r=(new CombatSimulator($rng))->simulate($this->c('character',20,5,2,0,0,100,1.5),$this->c('monster',6,1,1,0,0,0,1.5,10));$a=$r->rounds()[0]->actions()[0];$this->assertTrue($a->critical());$this->assertSame(7,$a->damage());$this->assertSame(CombatResultStatus::CHARACTER_VICTORY,$r->status());$this->assertCount(1,$r->rounds()[0]->actions());}public function test_initial_defeats_consume_no_randomness(){foreach([[0,10,CombatResultStatus::MONSTER_VICTORY],[10,0,CombatResultStatus::CHARACTER_VICTORY],[0,0,CombatResultStatus::DRAW]] as $case){$rng=new SequenceRandom([]);$c=new CombatantStats('character','c',20,$case[0],1,0,0,0,0,1,1,0);$m=new CombatantStats('monster','m',20,$case[1],1,0,0,0,0,1,1,0);$r=(new CombatSimulator($rng))->simulate($c,$m);$this->assertSame($case[2],$r->status());$this->assertSame(0,$r->roundsCount());$this->assertSame(0,$rng->calls);}}public function test_dtos_are_immutable(){foreach([CombatantStats::class,\App\Domain\Combat\Data\CombatAction::class,\App\Domain\Combat\Data\CombatRound::class,\App\Domain\Combat\Data\CombatResult::class] as $class){$r=new ReflectionClass($class);$this->assertTrue($r->isFinal());foreach($r->getProperties() as $p)$this->assertTrue($p->isPrivate());}}}
